// orderedStoreGroups returns item type keys in a fixed display order, skipping any absent types.
func orderedStoreGroups(storeItems map[string][]store.Item) []string {
	order := []string{"weapon", "armor", "equipment", "crafting", "fabrial", "mount", "vehicle", "pet"}
	var result []string
	for _, t := range order {
		if _, ok := storeItems[t]; ok {
			result = append(result, t)
		}
	}
	return result
}

func humanizeItemType(t string) string {
	switch t {
	case "weapon":
		return "Weapons"
	case "armor":
		return "Armor"
	case "equipment":
		return "Equipment"
	case "crafting":
		return "Crafting Materials"
	case "fabrial":
		return "Fabrials"
	case "mount":
		return "Mounts"
	case "vehicle":
		return "Vehicles"
	case "pet":
		return "Pets"
	default:
		return t
	}
}

